sys_ui_policy.script_false:
function onCondition() {
	// STRY0074135 if either parent template or child template is empty, then hide the appropriate fields, but show the form section
	if(g_form.getValue('u_parent_template') || g_form.getValue('tasker_process_instance')){
		g_form.setSectionDisplay("template_information", true);
		g_form.setDisplay('instance_notation', true);

	}else{
		g_form.setSectionDisplay("template_information", false);
		g_form.setDisplay('instance_notation', false);
	}
	if(g_form.getValue('u_parent_template')){
		g_form.setDisplay('u_parent_template', true);			
	}else{
		g_form.setDisplay('u_parent_template', false);
	}
	if(g_form.getValue('tasker_process_instance')){
		g_form.setDisplay('tasker_process_instance', true);
	}else{
		g_form.setDisplay('tasker_process_instance', false);
	}
	if(g_form.getValue('child_route_template')){
		g_form.setDisplay('child_route_template', true);
	}else{
		g_form.setDisplay('child_route_template', false);
	}
}

sys_ui_policy.script_true:
function onCondition() {
	// STRY0074135 if neither parent template or child template is empty, then hide the template area and all template fields
	g_form.setSectionDisplay("template_information", false);
	g_form.setDisplay('instance_notation', false);
	g_form.setDisplay('tasker_process_instance', false);
	g_form.setDisplay('child_route_template', false);
	g_form.setDisplay('u_parent_template', false);
}
